def validate(args, output):
    nums = args[0]
    n = len(nums)
    if not isinstance(output, list):
        return False
    import math
    base = sorted(nums)
    seen = set()
    for perm in output:
        if not isinstance(perm, list) or len(perm) != n:
            return False
        if sorted(perm) != base:
            return False
        key = tuple(perm)
        if key in seen:
            return False
        seen.add(key)
    return len(seen) == math.factorial(n)

