function validate(args, output) {
    const nums = args[0];
    const n = nums.length;
    if (!Array.isArray(output)) return false;
    const base = nums.slice().sort((a, b) => a - b).join(',');
    const seen = new Set();
    for (const perm of output) {
        if (!Array.isArray(perm) || perm.length !== n) return false;
        if (perm.slice().sort((a, b) => a - b).join(',') !== base) return false;
        const key = perm.join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    let fact = 1;
    for (let i = 2; i <= n; i++) fact *= i;
    return seen.size === fact;
}

