class Solution:
    def permute(self, nums):
        res = []
        used = [False] * len(nums)
        cur = []
        def back():
            if len(cur) == len(nums):
                res.append(cur[:])
                return
            for i in range(len(nums)):
                if used[i]:
                    continue
                used[i] = True
                cur.append(nums[i])
                back()
                cur.pop()
                used[i] = False
        back()
        res.sort()
        return res

